module adc_8bit (  
    input [7:0] obf_analog_in,  
    output reg [2:0] digital_out  
);  

always @(*) begin  
    if (obf_analog_in <= 85)  
        digital_out = 3'b000;  
    else if (obf_analog_in <= 170)  
        digital_out = 3'b001;  
    else  
        digital_out = 3'b010;  
end  
endmodule
